public inline fun <Error, A> result4k(block: Raise<Error>.() -> A): Result<A, Error> {
  contract { callsInPlace(block, InvocationKind.AT_MOST_ONCE) }
  return fold(block, { Failure(it) }, { Success(it) })
}

