class ProjectSLOCProcessor : AbstractProcessor() {

    override val id: String = "ProjectSLOCProcessor"
    override val visitor: DetektVisitor = SLOCVisitor()
    override val key: Key<Int> = sourceLinesKey
}

class SLOCVisitor : DetektVisitor() {

    override fun visitKtFile(file: KtFile) {
        val lines = file.text.split('\n')
        val sloc = SLOC().count(lines)
        file.putUserData(sourceLinesKey, sloc)
    }

    private class SLOC {

        private val comments = arrayOf("//", "/*", "*/", "*")

        fun count(lines: List<String>): Int =
            lines
                .map { it.trim() }
                .count { trim -> trim.isNotEmpty() && !comments.any { trim.startsWith(it) } }
    }
}

val sourceLinesKey = Key<Int>("sloc")

package karakum.query

fun getTypeName(
    source: String,
    keyword: String,
    fixAction: Boolean = false,
): String {
    var name = source
        .substringAfter("$keyword ")
        .substringBefore(" ")
        .substringBefore("<")

    if (fixAction && name.endsWith("Action")) {
        name = "Mutation$name"
    }

    return name
}

fun formatParameters(parameters: List<String>): String {
    if (parameters.isEmpty())
        return ""

    return parameters.joinToString(", ", "<", ">")
}

fun parseTypeParameters(
    source: String,
): List<String> {
    if (!source.endsWith(">")) {
        return emptyList<String>()
    }

    return source.substringAfter("<")
        .removeSuffix(">")
        .replace(" extends QueryOptions<any, any, any, ", " extends QueryOptions<*, *, *, ")
        .replace(" any[]", " ReadonlyArray<*>")
        .splitToSequence(", ")
        .map { it.substringBefore(" = ") }
        .map { it.replace(" extends ", ": ") }
        .map { if (it.endsWith(": Function")) "$it<*>" else it }
        .toList()
}

import org.gradle.api.Project
